import React, {
  forwardRef,
  useCallback,
  useContext,
  useState,
  useEffect,
  useRef,
  useMemo,
} from 'react';
import { Previous } from 'grommet-icons/icons/Previous';
import { Next } from 'grommet-icons/icons/Next';
import { useLayoutEffect } from '../../utils/use-isomorphic-layout-effect';

import { Box } from '../Box';
import { Button } from '../Button';
import { TabsContext } from './TabsContext';
import { ResponsiveContext } from '../../contexts/ResponsiveContext';
import { StyledTabPanel, StyledTabs, StyledTabsHeader } from './StyledTabs';
import { normalizeColor, useId } from '../../utils';
import { MessageContext } from '../../contexts/MessageContext';
import { TabsPropTypes } from './propTypes';
import { useAnalytics } from '../../contexts/AnalyticsContext/AnalyticsContext';
import { useThemeValue } from '../../utils/useThemeValue';

const Tabs = forwardRef(
  (
    {
      alignControls,
      children,
      flex,
      justify = 'center',
      messages,
      responsive = true,
      ...rest
    },
    ref,
  ) => {
    const { theme, passThemeFlag } = useThemeValue();
    const { format } = useContext(MessageContext);
    const { activeIndex: propsActiveIndex, onActive } = rest;
    const [activeIndex, setActiveIndex] = useState(rest.activeIndex || 0);
    const [activeContent, setActiveContent] = useState();
    const [activeTitle, setActiveTitle] = useState();
    const [disableLeftArrow, setDisableLeftArrow] = useState();
    const [disableRightArrow, setDisableRightArrow] = useState();
    const [overflow, setOverflow] = useState();
    const [focusIndex, setFocusIndex] = useState(-1);
    const headerRef = useRef();
    const panelId = useId();
    const size = useContext(ResponsiveContext);
    const PreviousIcon = theme.tabs.header?.previousButton?.icon || Previous;
    const NextIcon = theme.tabs.header?.nextButton?.icon || Next;

    const sendAnalytics = useAnalytics();

    if (activeIndex !== propsActiveIndex && propsActiveIndex !== undefined) {
      setActiveIndex(propsActiveIndex);
    }

    // Safari v15.5 has an issue with scrolling when overflow='hidden'
    // and scroll-behavior='smooth'. For now we are detecting if the browser
    // is safari to workaround this issue. The issue should be resolved soon
    // and we can remove this. https://github.com/WebKit/WebKit/pull/1387
    const isSafari =
      typeof window !== 'undefined'
        ? /^((?!chrome|android).)*safari/i.test(window.navigator.userAgent)
        : true;

    /* eslint-disable no-param-reassign */
    delete rest.activeIndex;
    delete rest.onActive;
    /* eslint-enable no-param-reassign */

    const tabRefs = useMemo(
      () => React.Children.map(children, () => React.createRef()),
      [children],
    );
    const disabledIndexes = useMemo(
      () =>
        React.Children.map(children, (child) => {
          if (!React.isValidElement(child)) return true;
          return !!child.props.disabled;
        }) || [],
      [children],
    );

    const focusTab = useCallback(
      (index) => {
        if (index >= 0 && tabRefs[index]?.current) {
          tabRefs[index].current.focus();
        }
      },
      [tabRefs],
    );

    const findEnabledIndex = useCallback(
      (startIndex, direction) => {
        if (!disabledIndexes.length) return undefined;

        const normalizeIndex = (index) => {
          if (index < 0) return disabledIndexes.length - 1;
          if (index >= disabledIndexes.length) return 0;
          return index;
        };

        let nextIndex = normalizeIndex(startIndex);
        let attempts = 0;

        while (attempts < disabledIndexes.length) {
          if (!disabledIndexes[nextIndex]) {
            return nextIndex;
          }
          nextIndex = normalizeIndex(nextIndex + direction);
          attempts += 1;
        }

        return undefined;
      },
      [disabledIndexes],
    );

    const getClosestEnabledIndex = useCallback(
      (preferredIndex) => {
        if (!disabledIndexes.length) return undefined;

        const clampedIndex = Math.min(
          Math.max(preferredIndex, 0),
          disabledIndexes.length - 1,
        );

        if (!disabledIndexes[clampedIndex]) {
          return clampedIndex;
        }

        for (let offset = 1; offset < disabledIndexes.length; offset += 1) {
          const nextIndex = clampedIndex + offset;
          if (
            nextIndex < disabledIndexes.length &&
            !disabledIndexes[nextIndex]
          ) {
            return nextIndex;
          }

          const previousIndex = clampedIndex - offset;
          if (previousIndex >= 0 && !disabledIndexes[previousIndex]) {
            return previousIndex;
          }
        }

        return undefined;
      },
      [disabledIndexes],
    );

    const resolvedActiveIndex = useMemo(() => {
      if (!disabledIndexes.length) return undefined;

      if (activeIndex < 0 || activeIndex >= disabledIndexes.length) {
        return getClosestEnabledIndex(activeIndex);
      }

      if (disabledIndexes[activeIndex]) {
        return getClosestEnabledIndex(activeIndex);
      }

      return activeIndex;
    }, [activeIndex, disabledIndexes, getClosestEnabledIndex]);

    const activateTab = useCallback(
      (nextIndex) => {
        sendAnalytics({
          type: 'activateTab',
          element: tabRefs[nextIndex].current,
        });
        if (propsActiveIndex === undefined) {
          setActiveIndex(nextIndex);
        }
        if (onActive) {
          onActive(nextIndex);
        }
      },
      [onActive, propsActiveIndex, sendAnalytics, tabRefs],
    );

    const moveFocus = useCallback(
      (targetIndex) => {
        if (targetIndex === undefined) return;
        focusTab(targetIndex);
      },
      [focusTab],
    );

    const moveFocusByKey = useCallback(
      (currentIndex, direction) => {
        moveFocus(findEnabledIndex(currentIndex + direction, direction));
      },
      [findEnabledIndex, moveFocus],
    );

    const moveFocusToEdge = useCallback(
      (direction) => {
        const startIndex = direction > 0 ? 0 : tabRefs.length - 1;
        moveFocus(findEnabledIndex(startIndex, direction));
      },
      [findEnabledIndex, moveFocus, tabRefs.length],
    );

    const handleTabKeyDown = useCallback(
      (index, event) => {
        switch (event.key) {
          case 'ArrowRight':
            event.preventDefault();
            moveFocusByKey(index, 1);
            break;
          case 'ArrowLeft':
            event.preventDefault();
            moveFocusByKey(index, -1);
            break;
          case 'Home':
            event.preventDefault();
            moveFocusToEdge(1);
            break;
          case 'End':
            event.preventDefault();
            moveFocusToEdge(-1);
            break;
          case 'Enter':
          case ' ':
          case 'Spacebar':
            event.preventDefault();
            activateTab(index);
            break;
          default:
        }
      },
      [activateTab, moveFocusByKey, moveFocusToEdge],
    );

    // check if tab is in view
    const isVisible = useCallback(
      (index) => {
        if (tabRefs[index].current) {
          const tabRect = tabRefs[index].current.getBoundingClientRect();
          const headerRect = headerRef.current?.getBoundingClientRect();
          if (tabRect && headerRect) {
            // the -1 and +1 allow a little leniency when calculating if a tab
            // is in view. Without the -1 and +1 a tab could be fully in view
            // but isVisible will return false.
            return (
              tabRect.left >= headerRect.left - 1 &&
              tabRect.right <= headerRect.right + 1
            );
          }
        }
        return undefined;
      },
      [headerRef, tabRefs],
    );

    const updateArrowState = useCallback(() => {
      setDisableLeftArrow(isVisible(0));
      setDisableRightArrow(isVisible(tabRefs.length - 1));
    }, [tabRefs, isVisible]);

    const scrollTo = useCallback(
      (index, keyboard) => {
        const tabRect = tabRefs[index].current.getBoundingClientRect();
        const headerRect = headerRef.current.getBoundingClientRect();
        let amountHidden = 0;
        if (
          tabRect.left >= headerRect.left &&
          tabRect.left <= headerRect.right
        ) {
          amountHidden = tabRect.width - (headerRect.right - tabRect.left);
        } else if (
          tabRect.right >= headerRect.left &&
          tabRect.right <= headerRect.right
        ) {
          amountHidden = tabRect.width - (tabRect.right - headerRect.left);
          amountHidden = 0 - amountHidden;
        } else if (tabRect.left >= headerRect.right) {
          amountHidden = tabRect.right - headerRect.right;
        } else if (tabRect.right <= headerRect.left) {
          amountHidden = headerRect.left - tabRect.left;
          amountHidden = 0 - amountHidden;
        }
        // We are adding or subtracting 2 from amountHidden to
        // ensure the focusIndicator is visible when navigating
        // by keyboard
        if (keyboard) {
          if (amountHidden < 0) amountHidden -= 2;
          if (amountHidden > 0) amountHidden += 2;
        }
        if (isSafari) {
          headerRef.current.scrollBy({
            left: amountHidden,
          });
        } else {
          headerRef.current.scrollBy({
            left: amountHidden,
            behavior: 'smooth',
          });
        }

        // wait for scroll animation to finish
        // checks every 50 milliseconds for 1000 milliseconds
        // if the scroll animation has finished. Most scroll
        // animations will finish in 1000 milliseconds unless
        // the tab name is very long.
        if (isSafari) {
          updateArrowState();
        } else {
          const checkVisible = setInterval(() => {
            if (tabRefs[index].current && isVisible(index)) {
              updateArrowState();
              clearInterval(checkVisible);
            }
          }, 50);
          setTimeout(() => {
            updateArrowState();
            clearInterval(checkVisible);
          }, 1000);
        }
      },
      [tabRefs, headerRef, isVisible, updateArrowState, isSafari],
    );

    const moveByArrowKey = (direction) => {
      const previous = direction === 'previous';
      let index = direction === 'previous' ? 0 : tabRefs.length - 1;
      let scrolledToIndex;
      const moveBy = theme.tabs.step[size] - 1 || 0;

      while (
        scrolledToIndex === undefined &&
        ((previous && index < tabRefs.length - 1) || (!previous && index > 0))
      ) {
        if (
          !isVisible(index) &&
          ((previous && isVisible(index + 1)) ||
            (!previous && isVisible(index - 1)))
        ) {
          if (previous) {
            if (index - moveBy >= 0) {
              scrollTo(index - moveBy, false);
              scrolledToIndex = index - moveBy;
            } else {
              scrollTo(0, false);
              scrolledToIndex = 0;
            }
          } else if (index + moveBy < tabRefs.length) {
            scrollTo(index + moveBy, false);
            scrolledToIndex = index + moveBy;
          } else {
            scrollTo(tabRefs.length - 1, false);
            scrolledToIndex = tabRefs.length - 1;
          }
        }
        index = previous ? index + 1 : index - 1;
      }
    };

    useEffect(() => {
      // if the active tab isn't visible scroll to it
      if (
        overflow &&
        tabRefs &&
        resolvedActiveIndex !== undefined &&
        tabRefs[resolvedActiveIndex]?.current &&
        !isVisible(resolvedActiveIndex)
      )
        scrollTo(resolvedActiveIndex, true);
    }, [overflow, resolvedActiveIndex, tabRefs, isVisible, scrollTo]);

    useEffect(() => {
      // scroll focus item into view if it is not already visible
      if (overflow && focusIndex !== -1 && !isVisible(focusIndex))
        scrollTo(focusIndex, true);
      else if (overflow && focusIndex !== -1) {
        // If the browser scrolled the focused item into view and
        // the focusedTab is on the edge of the header container
        // scroll slightly further to show the focusIndicator
        const tabRect = tabRefs[focusIndex].current.getBoundingClientRect();
        const headerRect = headerRef.current.getBoundingClientRect();
        let amountHidden = 0;
        if (
          tabRect.left >= headerRect.left &&
          tabRect.right <= headerRect.right &&
          tabRect.right + 2 >= headerRect.right
        )
          amountHidden = 2;
        else if (
          tabRect.right <= headerRect.right &&
          tabRect.left >= headerRect.left &&
          tabRect.left - 2 <= headerRect.left
        )
          amountHidden = -2;
        headerRef.current.scrollBy({
          left: amountHidden,
        });
      }
    }, [overflow, tabRefs, focusIndex, isVisible, scrollTo]);

    useLayoutEffect(() => {
      const onResize = () => {
        // check if tabs are overflowing
        if (headerRef.current.scrollWidth > headerRef.current.offsetWidth) {
          setOverflow(true);
        } else setOverflow(false);
        updateArrowState();
      };
      onResize();
      window.addEventListener('resize', onResize);
      return () => window.removeEventListener('resize', onResize);
    }, [
      tabRefs,
      disableLeftArrow,
      disableRightArrow,
      activeIndex,
      headerRef,
      overflow,
      updateArrowState,
    ]);

    useLayoutEffect(() => {
      if (focusIndex === -1 || !headerRef.current) return;

      const { activeElement } = document;
      if (headerRef.current.contains(activeElement)) return;

      const nextFocusIndex = getClosestEnabledIndex(focusIndex);
      if (nextFocusIndex === undefined) {
        setFocusIndex(-1);
        return;
      }

      setFocusIndex(nextFocusIndex);
      focusTab(nextFocusIndex);
    }, [children, focusIndex, focusTab, getClosestEnabledIndex]);

    const getTabsContext = useCallback(
      (index) => ({
        activeIndex: resolvedActiveIndex,
        active: resolvedActiveIndex === index,
        focusable:
          focusIndex === -1
            ? resolvedActiveIndex === index
            : focusIndex === index,
        index,
        panelId,
        ref: tabRefs[index],
        onActivate: () => activateTab(index),
        onKeyDown: (event) => handleTabKeyDown(index, event),
        onNext: () => moveFocusByKey(index, 1),
        onPrevious: () => moveFocusByKey(index, -1),
        onFirst: () => moveFocusToEdge(1),
        onLast: () => moveFocusToEdge(-1),
        setActiveContent,
        setActiveTitle,
        setFocusIndex,
      }),
      [
        focusIndex,
        activateTab,
        handleTabKeyDown,
        moveFocusByKey,
        moveFocusToEdge,
        panelId,
        resolvedActiveIndex,
        tabRefs,
      ],
    );

    const tabs = React.Children.map(children, (child, index) => (
      <TabsContext.Provider value={getTabsContext(index)}>
        {/* possible to have undefined child. in that case, you can't
        do cloneElement */}
        {child
          ? // cloneElement is needed for backward compatibility with custom
            // styled components that rely on props.active. We should reassess
            // if it is still necessary in our next major release.
            React.cloneElement(child, { active: resolvedActiveIndex === index })
          : child}
      </TabsContext.Provider>
    ));

    const tabsHeaderStyles = {};
    if (theme.tabs.header && theme.tabs.header.border) {
      let borderColor =
        theme.tabs.header.border.color || theme.global.control.border.color;
      borderColor = normalizeColor(borderColor, theme);

      tabsHeaderStyles.border = {
        side: theme.tabs.header.border.side,
        size: theme.tabs.header.border.size,
        style: theme.tabs.header.border.style,
        color: borderColor,
      };
    }

    const tabContentTitle = `${activeTitle || ''} ${format({
      id: 'tabs.tabContents',
      messages,
    })}`;

    return (
      <StyledTabs
        ref={ref}
        flex={flex}
        responsive={responsive}
        {...passThemeFlag}
        {...rest}
        background={theme.tabs.background}
      >
        <Box
          alignSelf={alignControls || theme.tabs.header?.alignSelf}
          flex={false}
          direction={overflow ? 'row' : 'column'}
          {...tabsHeaderStyles}
        >
          {overflow && (
            <Button
              a11yTitle={format({
                id: 'tabs.previousTab',
                messages,
              })}
              disabled={disableLeftArrow}
              // removed from tabIndex, button is redundant for keyboard users
              tabIndex={-1}
              onClick={() => moveByArrowKey('previous')}
            >
              <Box pad={theme.tabs.header.previousButton.pad}>
                <PreviousIcon
                  color={
                    disableLeftArrow
                      ? theme.button.disabled.color
                      : theme.global.colors.text
                  }
                />
              </Box>
            </Button>
          )}
          <StyledTabsHeader
            role="tablist"
            ref={headerRef}
            direction="row"
            justify={overflow ? 'start' : justify}
            flex={!!overflow}
            wrap={false}
            overflow={overflow ? 'hidden' : 'visible'}
            background={theme.tabs.header.background}
            gap={theme.tabs.gap}
            pad={overflow ? '2px' : undefined}
            margin={overflow ? '-2px' : undefined}
            {...passThemeFlag}
          >
            {tabs}
          </StyledTabsHeader>
          {overflow && (
            <Button
              a11yTitle={format({
                id: 'tabs.nextTab',
                messages,
              })}
              disabled={disableRightArrow}
              // removed from tabIndex, button is redundant for keyboard users
              tabIndex={-1}
              onClick={() => moveByArrowKey('next')}
            >
              <Box pad={theme.tabs.header?.nextButton?.pad}>
                <NextIcon
                  color={
                    disableRightArrow
                      ? theme.button.disabled.color
                      : theme.global.colors.text
                  }
                />
              </Box>
            </Button>
          )}
        </Box>

        <StyledTabPanel
          id={panelId}
          flex={flex}
          aria-label={tabContentTitle}
          role="tabpanel"
          {...passThemeFlag}
        >
          {activeContent}
        </StyledTabPanel>
      </StyledTabs>
    );
  },
);

Tabs.displayName = 'Tabs';
Tabs.propTypes = TabsPropTypes;

export { Tabs };
